using UnityEngine;
using UnityEditor;

// 找到场景中的 GameObject 并添加组件
var homeGO = GameObject.Find("HomeManager");
var buildingGO = GameObject.Find("BuildingManager");
var resourceGO = GameObject.Find("ResourceManager");

if (homeGO != null)
{
    if (homeGO.GetComponent("HomeManager") == null)
    {
        homeGO.AddComponent<Sttop5.Modules.HomeBase.HomeManager>();
        Debug.Log("Added HomeManager component");
    }
    else
    {
        Debug.Log("HomeManager component already exists");
    }
}
else
{
    Debug.LogError("HomeManager GameObject not found!");
}

if (buildingGO != null)
{
    if (buildingGO.GetComponent("BuildingManager") == null)
    {
        buildingGO.AddComponent<Sttop5.Modules.HomeBase.BuildingManager>();
        Debug.Log("Added BuildingManager component");
    }
    else
    {
        Debug.Log("BuildingManager component already exists");
    }
}
else
{
    Debug.LogError("BuildingManager GameObject not found!");
}

if (resourceGO != null)
{
    if (resourceGO.GetComponent("ResourceManager") == null)
    {
        resourceGO.AddComponent<Sttop5.Modules.HomeBase.ResourceManager>();
        Debug.Log("Added ResourceManager component");
    }
    else
    {
        Debug.Log("ResourceManager component already exists");
    }
}
else
{
    Debug.LogError("ResourceManager GameObject not found!");
}

// 设置 BuildingManager 为 BuildingManager GO 的子级
if (buildingGO != null)
{
    buildingGO.transform.SetParent(homeGO != null ? homeGO.transform : null);
}
if (resourceGO != null)
{
    resourceGO.transform.SetParent(homeGO != null ? homeGO.transform : null);
}

Debug.Log("Scene setup complete!");

