{
    var rmGO = homeGO.transform.Find("ResourceManager");
    if (rmGO != null)
    {
        var rm = rmGO.GetComponent<Sttop5.Modules.HomeBase.ResourceManager>();
        resourceProp.objectReferenceValue = rm;
        Debug.Log($"Set _resourceManager: {(rm != null ? "OK" : "NULL")}");
    }
    else
    {
        Debug.LogWarning("ResourceManager child not found under HomeManager");
    }
}
else
{
    Debug.LogWarning("_resourceManager property not found");
}

so.ApplyModifiedProperties();
Debug.Log("HomeManager references configured!");

