using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using UnityEditor.SceneManagement;

namespace Sttop5.Modules.HomeBase.Editor
{
    public static class HomeSceneSetup
    {
        [MenuItem("Tools/Setup HomeScene")]
        public static void Setup()
        {
            // ===== 配置 Canvas =====
            var canvasGO = GameObject.Find("Canvas");
            if (canvasGO != null)
            {
                var canvas = canvasGO.GetComponent<Canvas>();
                if (canvas == null) canvas = canvasGO.AddComponent<Canvas>();
                canvas.renderMode = RenderMode.ScreenSpaceOverlay;

                var scaler = canvasGO.GetComponent<CanvasScaler>();
                if (scaler == null) scaler = canvasGO.AddComponent<CanvasScaler>();
                scaler.uiScaleMode = CanvasScaler.ScaleMode.ScaleWithScreenSize;
                scaler.referenceResolution = new Vector2(1920, 1080);
                scaler.matchWidthOrHeight = 0.5f;

                if (canvasGO.GetComponent<GraphicRaycaster>() == null)
                    canvasGO.AddComponent<GraphicRaycaster>();

                Debug.Log("[HomeSceneSetup] Canvas configured");
            }

            // ===== 配置 ResourceBar =====
            var resourceBarGO = GameObject.Find("ResourceBar");
            if (resourceBarGO != null)
            {
                if (canvasGO != null)
                    resourceBarGO.transform.SetParent(canvasGO.transform, false);

                var rect = resourceBarGO.GetComponent<RectTransform>();
                if (rect == null) rect = resourceBarGO.AddComponent<RectTransform>();
                rect.anchorMin = new Vector2(0, 1);
                rect.anchorMax = new Vector2(1, 1);
                rect.pivot = new Vector2(0.5f, 1);
                rect.anchoredPosition = Vector2.zero;
                rect.sizeDelta = new Vector2(0, 60);

                var bgImg = resourceBarGO.GetComponent<Image>();
                if (bgImg == null) bgImg = resourceBarGO.AddComponent<Image>();
                bgImg.color = new Color(0.1f, 0.1f, 0.15f, 0.9f);

                var hlg = resourceBarGO.GetComponent<HorizontalLayoutGroup>();
                if (hlg == null) hlg = resourceBarGO.AddComponent<HorizontalLayoutGroup>();
                hlg.padding = new RectOffset(20, 20, 10, 10);
                hlg.spacing = 30f;
                hlg.childAlignment = TextAnchor.MiddleCenter;
                hlg.childControlWidth = true;
                hlg.childControlHeight = true;
                hlg.childForceExpandWidth = false;
                hlg.childForceExpandHeight = false;

                string[] labels = { "Gold: 0", "Diamond: 0", "Wood: 0", "Stone: 0", "Food: 0" };
                Color[] colors = {
                    new Color(1f, 0.85f, 0.1f),
                    new Color(0.3f, 0.8f, 1f),
                    new Color(0.7f, 0.5f, 0.2f),
                    new Color(0.6f, 0.6f, 0.6f),
                    new Color(0.4f, 0.8f, 0.3f)
                };
                string[] names = { "GoldText", "DiamondText", "WoodText", "StoneText", "FoodText" };

                for (int i = 0; i < labels.Length; i++)
                {
                    var textGO = new GameObject(names[i]);
                    textGO.transform.SetParent(resourceBarGO.transform, false);
                    var txt = textGO.AddComponent<Text>();
                    txt.text = labels[i];
                    txt.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
                    txt.fontSize = 22;
                    txt.color = colors[i];
                    txt.alignment = TextAnchor.MiddleCenter;

                    var outline = textGO.AddComponent<Outline>();
                    outline.effectColor = Color.black;
                    outline.effectDistance = new Vector2(1, -1);
                }

                Debug.Log("[HomeSceneSetup] ResourceBar configured with 5 resource texts");
            }

            // ===== 配置 CollectAllButton =====
            var collectBtnGO = GameObject.Find("CollectAllButton");
            if (collectBtnGO != null)
            {
                if (canvasGO != null)
                    collectBtnGO.transform.SetParent(canvasGO.transform, false);

                var rect = collectBtnGO.GetComponent<RectTransform>();
                if (rect == null) rect = collectBtnGO.AddComponent<RectTransform>();
                rect.anchorMin = new Vector2(1, 0);
                rect.anchorMax = new Vector2(1, 0);
                rect.pivot = new Vector2(1, 0);
                rect.anchoredPosition = new Vector2(-20, 20);
                rect.sizeDelta = new Vector2(200, 50);

                var btnImg = collectBtnGO.GetComponent<Image>();
                if (btnImg == null) btnImg = collectBtnGO.AddComponent<Image>();
                btnImg.color = new Color(0.2f, 0.7f, 0.3f);

                var btn = collectBtnGO.GetComponent<Button>();
                if (btn == null) btn = collectBtnGO.AddComponent<Button>();

                var btnTextGO = new GameObject("Text");
                btnTextGO.transform.SetParent(collectBtnGO.transform, false);
                var txt2 = btnTextGO.AddComponent<Text>();
                txt2.text = "Collect All";
                txt2.font = Resources.GetBuiltinResource<Font>("Arial.ttf");
                txt2.fontSize = 24;
                txt2.color = Color.white;
                txt2.alignment = TextAnchor.MiddleCenter;

                var btnTxtRect = btnTextGO.GetComponent<RectTransform>();
                btnTxtRect.anchorMin = Vector2.zero;
                btnTxtRect.anchorMax = Vector2.one;
                btnTxtRect.sizeDelta = Vector2.zero;

                Debug.Log("[HomeSceneSetup] CollectAllButton configured");
            }

            // ===== 配置 Main Camera =====
            var camGO = GameObject.Find("Main Camera");
            if (camGO != null)
            {
                var cam = camGO.GetComponent<Camera>();
                if (cam == null) cam = camGO.AddComponent<Camera>();
                cam.orthographic = true;
                cam.orthographicSize = 6f;
                cam.clearFlags = CameraClearFlags.SolidColor;
                cam.backgroundColor = new Color(0.15f, 0.2f, 0.3f);
                camGO.tag = "MainCamera";
                camGO.transform.position = new Vector3(4.5f, 3.5f, -10f);
                Debug.Log("[HomeSceneSetup] Main Camera configured");
            }

            // ===== 配置 Grid 区域背景 =====
            var gridGO = GameObject.Find("--- GRID ---");
            if (gridGO != null)
            {
                var gridBg = new GameObject("GridBackground");
                gridBg.transform.SetParent(gridGO.transform, false);
                gridBg.transform.position = new Vector3(4.5f, 3.5f, 0);

                var sr = gridBg.AddComponent<SpriteRenderer>();
                sr.color = new Color(0.2f, 0.35f, 0.2f, 0.3f);
                sr.sortingOrder = -1;
                gridBg.transform.localScale = new Vector3(10f, 8f, 1f);

                Debug.Log("[HomeSceneSetup] Grid background configured");
            }

            // ===== 添加 HomeMainUI 到 Canvas =====
            if (canvasGO != null)
            {
                var homeUI = canvasGO.GetComponent<HomeMainUI>();
                if (homeUI == null)
                {
                    homeUI = canvasGO.AddComponent<HomeMainUI>();
                    Debug.Log("[HomeSceneSetup] HomeMainUI added to Canvas");
                }
            }

            // ===== 标记场景为脏 =====
            EditorSceneManager.MarkSceneDirty(canvasGO.scene);

            Debug.Log("=== HomeScene setup complete! ===");
        }
    }
}

