args.script:
using UnityEngine;
using UnityEditor;
using Sttop5.Modules.HomeBase;

// ===== 设置背景图 =====
var bgTex = AssetDatabase.LoadAssetAtPath<Texture2D>("Assets/TJGenerators/History/Image_20260604_105831.png");
var grassBG = GameObject.Find("GrassBG");
if (grassBG != null && bgTex != null)
{
    var sr = grassBG.GetComponent<SpriteRenderer>();
    if (sr != null)
    {
        // 需要创建 Sprite 从 Texture2D
        var sprite = Sprite.Create(bgTex, new Rect(0, 0, bgTex.width, bgTex.height), new Vector2(0.5f, 0.5f), 100f);
        sr.sprite = sprite;
        Debug.Log("Background image applied to GrassBG!");
    }
}

// ===== 在场景中放置初始建筑 =====
var dataPath = "Assets/_Modules/HomeBase/Data/";

// 加载 BuildingData
var goldMineData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "GoldMine.asset");
var lumberData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "LumberMill.asset");
var quarryData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Quarry.asset");
var tdPortalData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Portal_TowerDefense.asset");
var m3PortalData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Portal_Match3.asset");
var fountainData = AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Fountain.asset");

// 建筑+位置配置
var buildings = new (BuildingData data, Vector2Int pos, string name, System.Type componentType)[] {
    (goldMineData, new Vector2Int(0, 0), "GoldMine", typeof(ResourceBuilding)),
    (lumberData, new Vector2Int(3, 0), "LumberMill", typeof(ResourceBuilding)),
    (quarryData, new Vector2Int(6, 0), "Quarry", typeof(ResourceBuilding)),
    (tdPortalData, new Vector2Int(1, 4), "Portal_TD", typeof(PortalBuilding)),
    (m3PortalData, new Vector2Int(5, 4), "Portal_Match3", typeof(PortalBuilding)),
    (fountainData, new Vector2Int(4, 3), "Fountain", typeof(BuildingBase)),
};

var gridParent = GameObject.Find("--- GRID ---");
if (gridParent == null) gridParent = new GameObject("--- GRID ---");

foreach (var b in buildings)
{
    if (b.data == null)
    {
        Debug.LogWarning($"Skipping {b.name}: BuildingData is null");
        continue;
    }

    // 计算世界位置 (网格中心)
    Vector3 worldPos = new Vector3(
        b.pos.x + b.data.gridSize.x * 0.5f,
        b.pos.y + b.data.gridSize.y * 0.5f,
        0f
    );

    // 创建建筑 GameObject
    var go = new GameObject(b.name);
    go.transform.SetParent(gridParent.transform);
    go.transform.position = worldPos;

    // 添加 SpriteRenderer
    var sr = go.AddComponent<SpriteRenderer>();
    if (b.data.icon != null)
    {
        sr.sprite = b.data.icon;
    }
    sr.sortingOrder = 5;

    // 调整缩放适配网格
    float scaleX = (float)b.data.gridSize.x;
    float scaleY = (float)b.data.gridSize.y;
    if (sr.sprite != null)
    {
        float pixelsPerUnit = sr.sprite.pixelsPerUnit > 0 ? sr.sprite.pixelsPerUnit : 100f;
        float spriteW = sr.sprite.rect.width / pixelsPerUnit;
        float spriteH = sr.sprite.rect.height / pixelsPerUnit;
        if (spriteW > 0 && spriteH > 0)
        {
            scaleX = b.data.gridSize.x / spriteW;
            scaleY = b.data.gridSize.y / spriteH;
        }
    }
    go.transform.localScale = new Vector3(scaleX, scaleY, 1f);

    // 添加对应的组件
    if (b.componentType != typeof(BuildingBase))
    {
        go.AddComponent(b.componentType);
    }
    else
    {
        go.AddComponent<BuildingBase>();
    }

    Debug.Log($"Placed building: {b.name} at grid {b.pos}, world {worldPos}");
}

EditorSceneManager.MarkSceneDirty(grassBG.scene);
Debug.Log("=== All buildings placed in scene! ===");

