var bgGO = UnityEngine.GameObject.Find("GrassBG");
if (bgGO != null)
{
    var sr = bgGO.GetComponent<UnityEngine.SpriteRenderer>();
    if (sr != null && sr.sprite != null)
    {
        var cam = UnityEngine.Camera.main;
        float camH = cam.orthographicSize * 2;  // 12
        float camW = camH * cam.aspect;          // ~21.3

        // 图片原始比例 2048:1024 = 2:1
        float imgAspect = 2048f / 1024f;  // 2.0
        float camAspect = camW / camH;     // ~1.78

        // 适配：保持图片比例，覆盖相机视野
        float scaleX, scaleY;
        if (imgAspect > camAspect)
        {
            // 图片更宽，以高度为准
            scaleY = camH;
            scaleX = camH * imgAspect;
        }
        else
        {
            // 图片更高，以宽度为准
            scaleX = camW;
            scaleY = camW / imgAspect;
        }

        bgGO.transform.localScale = new UnityEngine.Vector3(scaleX, scaleY, 1f);
        bgGO.transform.position = new UnityEngine.Vector3(cam.transform.position.x, cam.transform.position.y, 0f);

        UnityEngine.Debug.Log($"Cam view: {camW:F1} x {camH:F1}");
        UnityEngine.Debug.Log($"BG scale: {scaleX:F1} x {scaleY:F1} (aspect preserved: {imgAspect:F2})");
    }
}

