using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑存档数据。
    /// </summary>
    [Serializable]
    public class BuildingSaveEntry
    {
        public string buildingId;
        public int gridX;
        public int gridY;
        public int level;
    }

    /// <summary>
    /// 家园存档数据。
    /// </summary>
    [Serializable]
    public class HomeSaveData
    {
        public int wood;
        public int stone;
        public int food;
        public List<BuildingSaveEntry> buildings = new List<BuildingSaveEntry>();
    }

    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级、拆除和网格管理。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("网格配置")]
        [SerializeField] private Vector2Int _gridSize = new Vector2Int(10, 8);
        [SerializeField] private float _cellSize = 1f;
        [SerializeField] private Vector2 _gridOrigin = Vector2.zero;

        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;

        private BuildingBase[,] _grid;
        private Dictionary<Vector2Int, BuildingBase> _buildings = new Dictionary<Vector2Int, BuildingBase>();

        public Vector2Int GridSize => _gridSize;
        public float CellSize => _cellSize;
        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyDictionary<Vector2Int, BuildingBase> Buildings => _buildings;

        private void Awake()
        {
            _grid = new BuildingBase[_gridSize.x, _gridSize.y];
        }

        #region 网格坐标转换

        /// <summary>世界坐标 → 网格坐标。</summary>
        public Vector2Int WorldToGrid(Vector3 worldPos)
        {
            Vector2 local = (Vector2)worldPos - _gridOrigin;
            return new Vector2Int(
                Mathf.FloorToInt(local.x / _cellSize),
                Mathf.FloorToInt(local.y / _cellSize)
            );
        }

        /// <summary>网格坐标 → 世界坐标（中心点）。</summary>
        public Vector3 GridToWorld(Vector2Int gridPos)
        {
            return new Vector3(
                _gridOrigin.x + (gridPos.x + 0.5f) * _cellSize,
                _gridOrigin.y + (gridPos.y + 0.5f) * _cellSize,
                0f
            );
        }

        #endregion

        #region 放置与检测

        /// <summary>
        /// 检查指定位置是否可以放置建筑。
        /// </summary>
        public bool CanPlaceAt(Vector2Int pos, Vector2Int size)
        {
            for (int x = pos.x; x < pos.x + size.x; x++)
            {
                for (int y = pos.y; y < pos.y + size.y; y++)
                {
                    if (x < 0 || x >= _gridSize.x || y < 0 || y >= _gridSize.y)
                        return false;
                    if (_grid[x, y] != null)
                        return false;
                }
            }
            return true;
        }

        /// <summary>
        /// 放置建筑到指定网格位置。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector2Int gridPos)
        {
            if (!CanPlaceAt(gridPos, data.gridSize))
            {
                Debug.LogWarning($"[BuildingManager] 无法放置建筑: {data.buildingName} at {gridPos}");
                return null;
            }

            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            Vector3 worldPos = GridToWorld(gridPos);
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data, gridPos);

            // 占据网格
            for (int x = gridPos.x; x < gridPos.x + data.gridSize.x; x++)
            {
                for (int y = gridPos.y; y < gridPos.y + data.gridSize.y; y++)
                {
                    _grid[x, y] = building;
                }
            }

            _buildings[gridPos] = building;
            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {gridPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定位置的建筑。
        /// </summary>
        public bool RemoveBuilding(Vector2Int gridPos)
        {
            if (!_buildings.TryGetValue(gridPos, out BuildingBase building))
                return false;

            // 清空网格
            var data = building.Data;
            for (int x = gridPos.x; x < gridPos.x + data.gridSize.x; x++)
            {
                for (int y = gridPos.y; y < gridPos.y + data.gridSize.y; y++)
                {
                    _grid[x, y] = null;
                }
            }

            _buildings.Remove(gridPos);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置的建筑。
        /// </summary>
        public BuildingBase GetBuildingAt(Vector2Int gridPos)
        {
            if (gridPos.x < 0 || gridPos.x >= _gridSize.x || gridPos.y < 0 || gridPos.y >= _gridSize.y)
                return null;
            return _grid[gridPos.x, gridPos.y];
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var kvp in _buildings)
            {
                result.Add(new BuildingSaveEntry
                {
                    buildingId = kvp.Value.Data.buildingId,
                    gridX = kvp.Key.x,
                    gridY = kvp.Key.y,
                    level = kvp.Value.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                Vector2Int pos = new Vector2Int(entry.gridX, entry.gridY);
                if (!CanPlaceAt(pos, data.gridSize))
                {
                    Debug.LogWarning($"[BuildingManager] 存档位置冲突: {entry.buildingId} at {pos}");
                    continue;
                }

                Vector3 worldPos = GridToWorld(pos);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, pos, entry.level);

                for (int x = pos.x; x < pos.x + data.gridSize.x; x++)
                {
                    for (int y = pos.y; y < pos.y + data.gridSize.y; y++)
                    {
                        _grid[x, y] = building;
                    }
                }

                _buildings[pos] = building;
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = new GameObject($"Building_{data.buildingName}");
            go.transform.position = worldPos;
            go.transform.SetParent(transform);

            SpriteRenderer sr = go.AddComponent<SpriteRenderer>();
            sr.sprite = data.icon;
            if (sr.sprite == null)
            {
                sr.color = GetBuildingColor(data.buildingType);
            }
            sr.sortingOrder = 10;

            // 调整大小适配网格
            Vector2 size = new Vector2(data.gridSize.x * _cellSize, data.gridSize.y * _cellSize);
            go.transform.localScale = new Vector3(size.x, size.y, 1f);

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion

        #region 编辑器可视化

        private void OnDrawGizmosSelected()
        {
            Gizmos.color = new Color(0.5f, 0.5f, 0.5f, 0.3f);
            for (int x = 0; x < _gridSize.x; x++)
            {
                for (int y = 0; y < _gridSize.y; y++)
                {
                    Vector3 center = new Vector3(
                        _gridOrigin.x + (x + 0.5f) * _cellSize,
                        _gridOrigin.y + (y + 0.5f) * _cellSize,
                        0f
                    );
                    Gizmos.DrawWireCube(center, new Vector3(_cellSize, _cellSize, 0.01f));
                }
            }
        }

        #endregion
    }
}

using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑基类，所有建筑类型继承此类。
    /// 管理建筑的等级、位置、升级和拆除。
    /// </summary>
    public class BuildingBase : MonoBehaviour
    {
        [Header("建筑配置")]
        [SerializeField] protected BuildingData _data;

        protected int _currentLevel = 1;
        protected Vector2Int _gridPosition;
        protected bool _isPlaced = false;
        protected float _productionTimer;

        #region 属性

        public BuildingData Data => _data;
        public int CurrentLevel => _currentLevel;
        public Vector2Int GridPosition => _gridPosition;
        public bool IsPlaced => _isPlaced;
        public bool IsMaxLevel => _currentLevel >= _data.MaxLevel;
        public BuildingLevel CurrentLevelData => _data.GetLevelData(_currentLevel);

        #endregion

        #region 初始化

        /// <summary>
        /// 初始化建筑，在放置到网格时调用。
        /// </summary>
        public virtual void Initialize(BuildingData data, Vector2Int gridPos)
        {
            _data = data;
            _gridPosition = gridPos;
            _currentLevel = 1;
            _isPlaced = true;
            _productionTimer = 0f;
        }

        /// <summary>
        /// 从存档恢复建筑状态。
        /// </summary>
        public virtual void RestoreFromSave(BuildingData data, Vector2Int gridPos, int level)
        {
            _data = data;
            _gridPosition = gridPos;
            _currentLevel = Mathf.Clamp(level, 1, data.MaxLevel);
            _isPlaced = true;
            _productionTimer = 0f;
        }

        #endregion

        #region 升级与拆除

        /// <summary>
        /// 升级建筑。
        /// </summary>
        public virtual bool Upgrade()
        {
            if (IsMaxLevel)
            {
                Debug.LogWarning($"[BuildingBase] 建筑已满级: {_data.buildingName}");
                return false;
            }

            var levelData = _data.GetLevelData(_currentLevel + 1);
            var profile = PlayerProfile.Instance;
            if (profile == null || !profile.HasEnoughGold(levelData.upgradeCost))
            {
                Debug.LogWarning($"[BuildingBase] 金币不足，无法升级: {_data.buildingName}");
                return false;
            }

            profile.SpendGold(levelData.upgradeCost, "building_upgrade");
            _currentLevel++;
            OnUpgraded();
            Debug.Log($"[BuildingBase] 建筑升级: {_data.buildingName} Lv.{_currentLevel}");
            return true;
        }

        /// <summary>
        /// 拆除建筑，返还部分资源。
        /// </summary>
        public virtual int Demolish()
        {
            int refund = GetSellValue();
            var profile = PlayerProfile.Instance;
            profile?.AddGold(refund, "building_demolish");
            _isPlaced = false;
            Debug.Log($"[BuildingBase] 建筑拆除: {_data.buildingName}, 返还 {refund} 金币");
            Destroy(gameObject);
            return refund;
        }

        /// <summary>
        /// 获取出售价值（建造费用的 60%）。
        /// </summary>
        public int GetSellValue()
        {
            int totalCost = 0;
            for (int i = 1; i <= _currentLevel; i++)
            {
                var ld = _data.GetLevelData(i);
                totalCost += i == 1 ? ld.buildCost : ld.upgradeCost;
            }
            return Mathf.RoundToInt(totalCost * 0.6f);
        }

        #endregion

        #region 子类重写

        /// <summary>升级后的回调。</summary>
        protected virtual void OnUpgraded() { }

        /// <summary>每帧更新（用于资源产出等）。</summary>
        protected virtual void BuildingUpdate() { }

        #endregion

        private void Update()
        {
            if (!_isPlaced) return;
            BuildingUpdate();
        }
    }
}

