using UnityEngine;
using Sttop5.Modules.HomeBase;

var dataPath = "Assets/_Modules/HomeBase/Data/";
var spritePath = "Assets/TJGenerators/History/";

// 加载 BuildingData
var tdPortalData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Portal_TowerDefense.asset");
var m3PortalData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Portal_Match3.asset");
var goldMineData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "GoldMine.asset");
var lumberData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "LumberMill.asset");
var quarryData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Quarry.asset");
var fountainData = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(dataPath + "Fountain.asset");

// 加载精灵
var tdSprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105744.png");
var m3Sprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105753.png");
var goldSprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105720.png");
var lumberSprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105725.png");
var quarrySprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105730.png");
var fountainSprite = UnityEditor.AssetDatabase.LoadAssetAtPath<Sprite>(spritePath + "Sprite_20260604_105842.png");

Debug.Log($"Data: TD={tdPortalData!=null} M3={m3PortalData!=null} Gold={goldMineData!=null}");
Debug.Log($"Sprites: TD={tdSprite!=null} M3={m3Sprite!=null} Gold={goldSprite!=null}");

void CreateBuilding(string name, BuildingData data, Sprite sprite, Vector3 pos, Vector3 scale, System.Type compType)
{
    var go = new GameObject(name);
    go.transform.position = pos;

    var sr = go.AddComponent<SpriteRenderer>();
    sr.sprite = sprite;
    sr.sortingOrder = 5;
    go.transform.localScale = scale;

    if (compType != null)
        go.AddComponent(compType);
    else
        go.AddComponent<BuildingBase>();

    // 设置 BuildingData
    var bb = go.GetComponent<BuildingBase>();
    if (bb != null && data != null)
    {
        var so = new UnityEditor.SerializedObject(bb);
        so.FindProperty("_data").objectReferenceValue = data;
        so.ApplyModifiedPropertiesWithoutUndo();
    }

    Debug.Log($"Created: {name} at {pos}");
}

// 塔防传送门 - 场景左侧偏上
CreateBuilding("Portal_TD", tdPortalData, tdSprite, 
    new Vector3(1f, 5.5f, 0f), new Vector3(0.1f, 0.15f, 1f), typeof(PortalBuilding));

// 消消乐传送门 - 场景右侧偏上
CreateBuilding("Portal_Match3", m3PortalData, m3Sprite, 
    new Vector3(7.5f, 5.5f, 0f), new Vector3(0.1f, 0.15f, 1f), typeof(PortalBuilding));

// 金矿 - 左下
CreateBuilding("GoldMine", goldMineData, goldSprite, 
    new Vector3(1f, 1.5f, 0f), new Vector3(0.1f, 0.1f, 1f), typeof(ResourceBuilding));

// 伐木场 - 中下
CreateBuilding("LumberMill", lumberData, lumberSprite, 
    new Vector3(4f, 1.2f, 0f), new Vector3(0.1f, 0.1f, 1f), typeof(ResourceBuilding));

// 采石场 - 右下
CreateBuilding("Quarry", quarryData, quarrySprite, 
    new Vector3(7f, 1.2f, 0f), new Vector3(0.1f, 0.1f, 1f), typeof(ResourceBuilding));

// 喷泉 - 中央
CreateBuilding("Fountain", fountainData, fountainSprite, 
    new Vector3(4.5f, 3.5f, 0f), new Vector3(0.05f, 0.05f, 1f), null);

UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(UnityEngine.SceneManagement.SceneManager.GetActiveScene());
Debug.Log("=== All buildings + portals added! ===");

