using UnityEngine;
using UnityEditor;

// ===== 塔防传送门特效 =====
var portalTD = GameObject.Find("Portal_TD");
if (portalTD == null) { Debug.LogError("Portal_TD not found!"); return; }

// --- 1. 漩涡粒子系统 ---
var vortexGO = new GameObject("VortexParticles");
vortexGO.transform.SetParent(portalTD.transform, false);
vortexGO.transform.localPosition = Vector3.zero;

var ps = vortexGO.AddComponent<ParticleSystem>();
var main = ps.main;
main.simulationSpace = ParticleSystemSimulationSpace.Local;
main.startSpeed = 0.3f;
main.startSize = 0.15f;
main.startLifetime = 1.5f;
main.startColor = new Color(0.4f, 0.3f, 1f, 0.8f);
main.maxParticles = 80;
main.loop = true;
main.prewarm = true;

// 发射器 - 圆形边缘
var emission = ps.emission;
emission.rateOverTime = 30f;

var shape = ps.shape;
shape.shapeType = ParticleSystemShapeType.Circle;
shape.radius = 0.4f;
shape.radiusThickness = 0.8f; // 边缘

// 颜色渐变 - 从亮蓝紫到暗紫
var colorOverLifetime = ps.colorOverLifetime;
colorOverLifetime.enabled = true;
var gradient = new Gradient();
gradient.SetKeys(
    new GradientColorKey[] {
        new GradientColorKey(new Color(0.5f, 0.4f, 1f), 0f),
        new GradientColorKey(new Color(0.3f, 0.2f, 0.8f), 0.5f),
        new GradientColorKey(new Color(0.1f, 0.05f, 0.5f), 1f)
    },
    new GradientAlphaKey[] {
        new GradientAlphaKey(0.9f, 0f),
        new GradientAlphaKey(0.7f, 0.6f),
        new GradientAlphaKey(0f, 1f)
    }
);
colorOverLifetime.color = new ParticleSystem.MinMaxGradient(gradient);

// 旋转 - 绕Y轴（在2D中就是Z轴旋转）
var velocityOverLifetime = ps.velocityOverLifetime;
velocityOverLifetime.enabled = true;
velocityOverLifetime.orbitalX = 0f;
velocityOverLifetime.orbitalY = 0f;
velocityOverLifetime.orbitalZ = 1.5f; // 绕Z轴旋转
velocityOverLifetime.orbitalSpeedMultiplier = 1f;

// 向中心吸引
velocityOverLifetime.radial = -0.3f; // 向内吸引

// 大小渐变
var sizeOverLifetime = ps.sizeOverLifetime;
sizeOverLifetime.enabled = true;
sizeOverLifetime.size = new ParticleSystem.MinMaxCurve(1f, new AnimationCurve(
    new Keyframe(0f, 1f),
    new Keyframe(0.5f, 0.7f),
    new Keyframe(1f, 0.1f)
));

// 渲染 - 加法混合发光
var renderer = vortexGO.GetComponent<ParticleSystemRenderer>();
renderer.material = new Material(Shader.Find("Particles/Standard Unlit"));
renderer.material.SetFloat("_Mode", 1); // Additive
renderer.material.color = new Color(0.5f, 0.4f, 1f, 1f);
renderer.sortOrder = 10;

Debug.Log("TD Vortex particles created!");

// --- 2. 符文脉冲光晕 ---
var runeGO = new GameObject("RunePulse");
runeGO.transform.SetParent(portalTD.transform, false);
runeGO.transform.localPosition = Vector3.zero;

var runeLight = runeGO.AddComponent<Light>();
runeLight.color = new Color(0.4f, 0.3f, 1f);
runeLight.intensity = 1.5f;
runeLight.range = 1.5f;
runeLight.shadows = LightShadows.None;

Debug.Log("TD Rune pulse light created!");

