using UnityEngine;
using UnityEditor;
using System;
using System.Reflection;

// 通过反射从项目程序集加载类型
Type effectType = null;
foreach (var asm in AppDomain.CurrentDomain.GetAssemblies())
{
    if (asm.GetName().Name.StartsWith("Assembly-CSharp"))
    {
        effectType = asm.GetType("Sttop5.Modules.HomeBase.PortalEffectController");
        if (effectType != null) break;
    }
}

if (effectType == null)
{
    Debug.LogError("PortalEffectController not found in any Assembly-CSharp");
    return;
}

var tdRune = GameObject.Find("RunePulse");
if (tdRune != null && tdRune.GetComponent(effectType) == null)
{
    tdRune.AddComponent(effectType);
    Debug.Log("Added PortalEffectController to RunePulse");
}

var m3Glow = GameObject.Find("PinkGlow");
if (m3Glow != null && m3Glow.GetComponent(effectType) == null)
{
    m3Glow.AddComponent(effectType);
    Debug.Log("Added PortalEffectController to PinkGlow");
}

EditorSceneManager.MarkSceneDirty(UnityEngine.SceneManagement.SceneManager.GetActiveScene());
Debug.Log("Done!");

using UnityEngine;
using UnityEditor;

// 直接用内联方式给光晕加脉冲动画脚本
// 不依赖 PortalEffectController 类

var tdRune = GameObject.Find("RunePulse");
if (tdRune != null)
{
    var tdLight = tdRune.GetComponent<Light>();
    if (tdLight != null)
    {
        var anim = tdRune.AddComponent<Animation>();
        var clip = new AnimationClip();
        clip.legacy = true;
        clip.wrapMode = WrapMode.PingPong;

        // 光强度动画
        var curve = AnimationCurve.EaseInOut(0f, 1f, 1f, 3f);
        clip.SetCurve("", typeof(Light), "m_Intensity", curve);

        // 光范围动画
        var rangeCurve = AnimationCurve.EaseInOut(0f, 1.5f, 1f, 2.5f);
        clip.SetCurve("", typeof(Light), "m_Range", rangeCurve);

        clip.name = "RunePulse";
        anim.AddClip(clip, "RunePulse");
        anim.Play("RunePulse");
        Debug.Log("TD RunePulse animation set");
    }
}

var m3Glow = GameObject.Find("PinkGlow");
if (m3Glow != null)
{
    var m3Light = m3Glow.GetComponent<Light>();
    if (m3Light != null)
    {
        var anim = m3Glow.AddComponent<Animation>();
        var clip = new AnimationClip();
        clip.legacy = true;
        clip.wrapMode = WrapMode.PingPong;

        var curve = AnimationCurve.EaseInOut(0f, 1f, 1f, 3f);
        clip.SetCurve("", typeof(Light), "m_Intensity", curve);

        var rangeCurve = AnimationCurve.EaseInOut(0f, 1.5f, 1f, 2.5f);
        clip.SetCurve("", typeof(Light), "m_Range", rangeCurve);

        clip.name = "PinkGlow";
        anim.AddClip(clip, "PinkGlow");
        anim.Play("PinkGlow");
        Debug.Log("Match3 PinkGlow animation set");
    }
}

EditorSceneManager.MarkSceneDirty(UnityEngine.SceneManagement.SceneManager.GetActiveScene());
Debug.Log("Portal pulse animations added!");

